    pub fn parse_ticker(&self, mut ticker: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // Spot fetchTicker, fetchTickers
        //
        //     {
        //         "close": "62393.47",
        //         "high": "64106.41",
        //         "last": "62393.47",
        //         "low": "59650.01",
        //         "market": "BTCUSDT",
        //         "open": "61616.15",
        //         "period": 86400,
        //         "value": "28711273.4065667262",
        //         "volume": "461.76557205",
        //         "volume_buy": "11.41506354",
        //         "volume_sell": "7.3240169"
        //     }
        //
        // Swap fetchTicker, fetchTickers
        //
        //     {
        //         "close": "62480.08",
        //         "high": "64100",
        //         "index_price": "62443.05",
        //         "last": "62480.08",
        //         "low": "59600",
        //         "mark_price": "62443.05",
        //         "market": "BTCUSDT",
        //         "open": "61679.98",
        //         "period": 86400,
        //         "value": "180226025.69791713065326633165",
        //         "volume": "2900.2218",
        //         "volume_buy": "7.3847",
        //         "volume_sell": "6.1249"
        //     }
        //
        let mut marketType: Value = ternary(is_true(&(Value::Bool(in_op(&ticker, &Value::Str("mark_price".to_string()))))), Value::Str("swap".to_string()), Value::Str("spot".to_string()));
        let mut marketId: Value = self.safe_string_k(ticker.clone(), "market", &[]);
        let mut symbol: Value = self.safe_symbol(marketId.clone(), &[market.clone(), Value::Null, marketType.clone()]);
        return self.safe_ticker(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("timestamp".to_string(), Value::Null);
        m.insert("datetime".to_string(), Value::Null);
        m.insert("high".to_string(), self.safe_string_k(ticker.clone(), "high", &[]));
        m.insert("low".to_string(), self.safe_string_k(ticker.clone(), "low", &[]));
        m.insert("bid".to_string(), Value::Null);
        m.insert("bidVolume".to_string(), self.safe_string_k(ticker.clone(), "volume_buy", &[]));
        m.insert("ask".to_string(), Value::Null);
        m.insert("askVolume".to_string(), self.safe_string_k(ticker.clone(), "volume_sell", &[]));
        m.insert("vwap".to_string(), Value::Null);
        m.insert("open".to_string(), self.safe_string_k(ticker.clone(), "open", &[]));
        m.insert("close".to_string(), self.safe_string_k(ticker.clone(), "close", &[]));
        m.insert("last".to_string(), self.safe_string_k(ticker.clone(), "last", &[]));
        m.insert("previousClose".to_string(), Value::Null);
        m.insert("change".to_string(), Value::Null);
        m.insert("percentage".to_string(), Value::Null);
        m.insert("average".to_string(), Value::Null);
        m.insert("baseVolume".to_string(), self.safe_string_k(ticker.clone(), "volume", &[]));
        m.insert("quoteVolume".to_string(), Value::Null);
        m.insert("markPrice".to_string(), self.safe_string_k(ticker.clone(), "mark_price", &[]));
        m.insert("indexPrice".to_string(), self.safe_string_k(ticker.clone(), "index_price", &[]));
        m.insert("info".to_string(), ticker.clone());
    m
}), &[market.clone()]);

    Value::Null
}

